"""Inverse SSA solvers using the TAO library.

This module provides inverse SSA solver classes that use PETSc's TAO
(Toolkit for Advanced Optimization) library for Tikhonov-regularized
inversion, along with iteration listener adaptors that bridge C++ callbacks
to Python listeners.
"""

import PISM
from PISM.util import Bunch
from PISM.logging import logError
from PISM.invert.ssa import InvSSASolver

import sys
import traceback


class InvSSASolver_Tikhonov(InvSSASolver):

    """Inverse SSA solver based on Tikhonov iteration using TAO.

    Uses PETSc's TAO optimization library to solve the inverse SSA problem
    with Tikhonov regularization. Supports multiple TAO algorithms (LMVM,
    CG, LCL, BLMVM) and both ``tauc`` and ``hardav`` design variables.

    Attributes
    ----------
    tao_types : dict
        Mapping from PISM algorithm names to the corresponding TAO algorithm
        strings. The mapping depends on the PETSc version.
    listeners : list
        List of iteration listener callables.
    solver : object or None
        The TAO solver instance, set after :meth:`solveInverse` is called.
    ip : object or None
        The inverse problem instance, set after :meth:`solveInverse` is called.
    """

    # Dictionary converting PISM algorithm names to the corresponding
    # TAO algorithms used to implement the Tikhonov minimization.
    tao_types = {}

    if PISM.PETSc.Sys.getVersion() < (3, 5, 0):
        tao_types = {'tikhonov_lmvm': 'tao_lmvm',
                     'tikhonov_cg': 'tao_cg',
                     'tikhonov_lcl': 'tao_lcl',
                     'tikhonov_blmvm': 'tao_blmvm'}
    else:
        tao_types = {'tikhonov_lmvm': 'lmvm',
                     'tikhonov_cg': 'cg',
                     'tikhonov_lcl': 'lcl',
                     'tikhonov_blmvm': 'blmvm'}


    def __init__(self, sbrun, method):
        """Initialize the Tikhonov inverse SSA solver.

        Parameters
        ----------
        sbrun : PISM.invert.ssa.SSAForwardRun
            The :class:`PISM.invert.ssa.SSAForwardRun` defining the forward problem.
        method : str
            Algorithm to use. Must be a key in :attr:`tao_types`.

        Raises
        ------
        ValueError
            If `method` is not a recognized TAO Tikhonov inversion method.
        """

        InvSSASolver.__init__(self, sbrun, method)
        self.listeners = []
        self.solver = None
        self.ip = None
        if self.tao_types.get(method) is None:
            raise ValueError("Unknown TAO Tikhonov inversion method: %s" % method)

    def addIterationListener(self, listener):
        """Add a listener to be called after each iteration.

        See :ref:`Listeners` for details on the listener interface.

        Parameters
        ----------
        listener : callable
            A callable to be invoked after each solver iteration.
        """
        self.listeners.append(listener)

    def addDesignUpdateListener(self, listener):
        """Add a listener to be called each time the design variable is changed.

        Parameters
        ----------
        listener : callable
            A callable to be invoked after each design variable update.
        """
        self.listeners.append(listener)

    def solveForward(self, zeta, out=None):
        r"""Solve the SSA given a parameterized design variable value :math:`\zeta`.

        See :cpp:class:`IP_TaucParam` for a discussion of parameterizations.

        Parameters
        ----------
        zeta : Array
            :cpp:class:`Array` containing the parameterized design variable
            :math:`\zeta`.
        out : Array, optional
            :cpp:class:`Array` for storage of the computation result. If
            ``None``, a new array is returned.

        Returns
        -------
        Array
            :cpp:class:`Array` containing the computation result.

        Raises
        ------
        PISM.AlgorithmFailureException
            If the SSA linearization fails.
        """
        ssa = self.sbrun.solver

        reason = ssa.linearize_at(zeta)
        if reason.failed():
            raise PISM.AlgorithmFailureException(reason)
        if out is not None:
            out.copy_from(ssa.solution())
        else:
            out = ssa.solution()
        return out

    def solveInverse(self, zeta0, u_obs, zeta_inv):
        r"""Execute the Tikhonov inversion algorithm.

        Parameters
        ----------
        zeta0 : Array
            The best a priori guess for the value of the parameterized design
            variable :math:`\zeta`.
        u_obs : array::Vector
            :cpp:class:`array::Vector` of observed surface velocities.
        zeta_inv : Array
            Starting value of :math:`\zeta` for minimization of the Tikhonov
            functional.

        Returns
        -------
        TerminationReason
            A :cpp:class:`TerminationReason` indicating why the solver stopped.

        Raises
        ------
        RuntimeError
            If the design variable type is not ``'tauc'`` or ``'hardav'``.
        """
        eta = self.config.get_number("inverse.tikhonov.penalty_weight")

        design_var = self.sbrun.designVariable()
        if design_var == 'tauc':
            if self.method == 'tikhonov_lcl':
                problemClass = PISM.IP_SSATaucTaoTikhonovProblemLCL
                solverClass = PISM.IP_SSATaucTaoTikhonovProblemLCLSolver
                listenerClass = TaucLCLIterationListenerAdaptor
            else:
                problemClass = PISM.IP_SSATaucTaoTikhonovProblem
                solverClass = PISM.IP_SSATaucTaoTikhonovSolver
                listenerClass = TaucIterationListenerAdaptor
        elif design_var == 'hardav':
            if self.method == 'tikhonov_lcl':
                problemClass = PISM.IP_SSAHardavTaoTikhonovProblemLCL
                solverClass = PISM.IP_SSAHardavTaoTikhonovSolverLCL
                listenerClass = HardavLCLIterationListenerAdaptor
            else:
                problemClass = PISM.IP_SSAHardavTaoTikhonovProblem
                solverClass = PISM.IP_SSAHardavTaoTikhonovSolver
                listenerClass = HardavIterationListenerAdaptor
        else:
            raise RuntimeError("Unsupported design variable '%s' for InvSSASolver_Tikhonov. Expected 'tauc' or 'hardness'" % design_var)

        tao_type = self.tao_types[self.method]
        (stateFunctional, designFunctional) = PISM.invert.ssa.createTikhonovFunctionals(self.sbrun)

        self.ip = problemClass(self.sbrun.solver, zeta0, u_obs, eta, stateFunctional, designFunctional)
        self.solver = solverClass(self.sbrun.grid.com, tao_type, self.ip)

        max_it = int(self.config.get_number("inverse.max_iterations"))
        self.solver.setMaximumIterations(max_it)

        pl = [listenerClass(self, l) for l in self.listeners]

        for l in pl:
            self.ip.addListener(l)

        self.ip.setInitialGuess(zeta_inv)

        vecs = self.sbrun.modeldata.vecs
        if vecs.has('zeta_fixed_mask'):
            self.sbrun.solver.set_tauc_fixed_locations(vecs.zeta_fixed_mask)

        return self.solver.solve()

    def inverseSolution(self):
        """Return the design and state variables at the end of inversion.

        Returns
        -------
        zeta : Array
            The design variable solution.
        u : Array
            The state variable solution.
        """
        zeta = self.ip.designSolution()
        u = self.ip.stateSolution()
        return (zeta, u)


class TaucLCLIterationListenerAdaptor(PISM.IP_SSATaucTaoTikhonovProblemLCLListener):

    """Adaptor converting C++ iteration callbacks to Python listener calls.

    Bridges :cpp:class:`IP_SSATaucTaoTikhonovProblemLCLListener` callbacks to a
    standard Python-based listener. Used internally by
    :class:`InvSSASolver_Tikhonov`. Do not instantiate directly.

    Parameters
    ----------
    owner : InvSSASolver_Tikhonov
        The solver that constructed this adaptor.
    listener : callable
        The Python-based listener to forward callbacks to.
    """

    def __init__(self, owner, listener):
        """Initialize the LCL iteration listener adaptor.

        Parameters
        ----------
        owner : InvSSASolver_Tikhonov
            The :class:`InvSSASolver_Tikhonov` that constructed this adaptor.
        listener : callable
            The Python-based listener.
        """
        PISM.IP_SSATaucTaoTikhonovProblemLCLListener.__init__(self)
        self.owner = owner
        self.listener = listener

    def iteration(self, problem, eta, it, objVal, penaltyVal, d, diff_d, grad_d, u, diff_u, grad_u, constraints):
        """Handle an LCL iteration callback from the C++ solver.

        Gathers the arguments into a :class:`~PISM.util.Bunch` dictionary and
        passes it in standard form to the Python listener.

        Parameters
        ----------
        problem : IP_SSATaucTaoTikhonovProblemLCL
            The inverse problem instance.
        eta : float
            Current Tikhonov penalty weight.
        it : int
            Iteration number.
        objVal : float
            Design objective functional value.
        penaltyVal : float
            State penalty functional value.
        d : Array
            Current design variable :math:`\\zeta`.
        diff_d : Array
            Design variable step.
        grad_d : Array
            Gradient of the design functional.
        u : Array
            Current state variable.
        diff_u : Array
            State variable residual.
        grad_u : Array
            Gradient of the state functional.
        constraints : Array
            Constraint values.
        """

        data = Bunch(tikhonov_penalty=eta, JDesign=objVal, JState=penaltyVal,
                     zeta=d, zeta_step=diff_d, grad_JDesign=grad_d,
                     u=u, residual=diff_u, grad_JState=grad_u,
                     constraints=constraints)
        try:
            self.listener(self.owner, it, data)
        except Exception:
            logError("\nERROR: Exception occurred during an inverse solver listener callback:\n\n")
            traceback.print_exc(file=sys.stdout)
            raise


class TaucIterationListenerAdaptor(PISM.IP_SSATaucTaoTikhonovProblemListener):

    """Adaptor converting C++ iteration callbacks to Python listener calls.

    Bridges :cpp:class:`IP_SSATaucTaoTikhonovProblemListener` callbacks to a
    standard Python-based listener. Used internally by
    :class:`InvSSASolver_Tikhonov`. Do not instantiate directly.

    Parameters
    ----------
    owner : InvSSASolver_Tikhonov
        The solver that constructed this adaptor.
    listener : callable
        The Python-based listener to forward callbacks to.
    """

    def __init__(self, owner, listener):
        """Initialize the tauc iteration listener adaptor.

        Parameters
        ----------
        owner : InvSSASolver_Tikhonov
            The :class:`InvSSASolver_Tikhonov` that constructed this adaptor.
        listener : callable
            The Python-based listener.
        """
        PISM.IP_SSATaucTaoTikhonovProblemListener.__init__(self)
        self.owner = owner
        self.listener = listener

    def iteration(self, problem, eta, it, objVal, penaltyVal, d, diff_d, grad_d, u, diff_u, grad_u, grad):
        """Handle an iteration callback from the C++ solver.

        Gathers the arguments into a :class:`~PISM.util.Bunch` dictionary and
        passes it in standard form to the Python listener.

        Parameters
        ----------
        problem : IP_SSATaucTaoTikhonovProblem
            The inverse problem instance.
        eta : float
            Current Tikhonov penalty weight.
        it : int
            Iteration number.
        objVal : float
            Design objective functional value.
        penaltyVal : float
            State penalty functional value.
        d : Array
            Current design variable :math:`\\zeta`.
        diff_d : Array
            Design variable step.
        grad_d : Array
            Gradient of the design functional.
        u : Array
            Current state variable.
        diff_u : Array
            State variable residual.
        grad_u : Array
            Gradient of the state functional.
        grad : Array
            Gradient of the Tikhonov functional.
        """
        data = Bunch(tikhonov_penalty=eta, JDesign=objVal, JState=penaltyVal,
                     zeta=d, zeta_step=diff_d, grad_JDesign=grad_d,
                     u=u, residual=diff_u, grad_JState=grad_u, grad_JTikhonov=grad)
        try:
            self.listener(self.owner, it, data)
        except Exception:
            logError("\nERROR: Exception occurred during an inverse solver listener callback:\n\n")
            traceback.print_exc(file=sys.stdout)
            raise


